import{_ as a,o as i,c as l,ag as o}from"./chunks/framework.ByAj6Cie.js";const m=JSON.parse('{"title":"Selección de Cables","description":"","frontmatter":{},"headers":[],"relativePath":"es/cables/selection/cable-selection.md","filePath":"es/cables/selection/cable-selection.md"}'),n={name:"es/cables/selection/cable-selection.md"};function c(r,e,s,t,d,u){return i(),l("div",null,[...e[0]||(e[0]=[o('<h1 id="seleccion-de-cables" tabindex="-1">Selección de Cables <a class="header-anchor" href="#seleccion-de-cables" aria-label="Permalink to &quot;Selección de Cables&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción General <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción General&quot;">​</a></h2><p>La selección de cables es el proceso de elegir el tipo, tamaño y construcción adecuados para una aplicación específica dentro de un sistema industrial.</p><p>Integra consideraciones eléctricas, mecánicas y ambientales para garantizar una operación segura, un desempeño confiable y el cumplimiento de normas aplicables.</p><hr><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>El objetivo de la selección de cables es:</p><ul><li>Asegurar que el cable transporte la carga de forma segura</li><li>Mantener niveles adecuados de voltaje en el equipo</li><li>Proteger las señales contra interferencias</li><li>Resistir condiciones de instalación y del entorno</li><li>Cumplir con normas de seguridad y regulación</li></ul><p>Una correcta selección impacta directamente en la confiabilidad y el desempeño a largo plazo del sistema.</p><hr><h2 id="como-funciona" tabindex="-1">Cómo Funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo Funciona&quot;">​</a></h2><p>La selección de cables integra múltiples factores en una sola decisión:</p><ul><li>Requisitos eléctricos (corriente, voltaje, distancia)</li><li>Tipo de aplicación (potencia, control, comunicación, instrumentación)</li><li>Condiciones de instalación (ruteo, entorno, esfuerzo mecánico)</li><li>Restricciones del sistema (ruido, flexibilidad, protección)</li></ul><p>El proceso consiste en evaluar cada factor y seleccionar un cable que cumpla con todos simultáneamente.</p><hr><h2 id="proceso-de-seleccion" tabindex="-1">Proceso de Selección <a class="header-anchor" href="#proceso-de-seleccion" aria-label="Permalink to &quot;Proceso de Selección&quot;">​</a></h2><h3 id="_1-definir-la-aplicacion" tabindex="-1">1. Definir la Aplicación <a class="header-anchor" href="#_1-definir-la-aplicacion" aria-label="Permalink to &quot;1. Definir la Aplicación&quot;">​</a></h3><p>Identificar la función del cable:</p><ul><li>Potencia</li><li>Control</li><li>Comunicación</li><li>Instrumentación</li></ul><p>Esto determina el tipo base de cable.</p><hr><h3 id="_2-determinar-requisitos-electricos" tabindex="-1">2. Determinar Requisitos Eléctricos <a class="header-anchor" href="#_2-determinar-requisitos-electricos" aria-label="Permalink to &quot;2. Determinar Requisitos Eléctricos&quot;">​</a></h3><p>Establecer parámetros clave:</p><ul><li>Nivel de voltaje</li><li>Corriente de carga (FLC)</li><li>Tipo de sistema (monofásico o trifásico)</li></ul><p>Estos definen las exigencias eléctricas.</p><hr><h3 id="_3-dimensionar-el-conductor" tabindex="-1">3. Dimensionar el Conductor <a class="header-anchor" href="#_3-dimensionar-el-conductor" aria-label="Permalink to &quot;3. Dimensionar el Conductor&quot;">​</a></h3><p>Seleccionar el tamaño del conductor en función de:</p><ul><li>Capacidad de corriente (ampacidad)</li><li>Caída de voltaje en la distancia</li><li>Factores de seguridad (por ejemplo, cargas continuas)</li></ul><p>El tamaño elegido debe cumplir con todas las condiciones.</p><hr><h3 id="_4-evaluar-condiciones-de-instalacion" tabindex="-1">4. Evaluar Condiciones de Instalación <a class="header-anchor" href="#_4-evaluar-condiciones-de-instalacion" aria-label="Permalink to &quot;4. Evaluar Condiciones de Instalación&quot;">​</a></h3><p>Considerar cómo y dónde se instalará el cable:</p><ul><li>Conduit, charola o aire libre</li><li>Temperatura ambiente</li><li>Agrupamiento con otros cables</li><li>Exposición a humedad, químicos o esfuerzo mecánico</li></ul><p>Aplicar factores de corrección si es necesario.</p><hr><h3 id="_5-considerar-ruido-e-integridad-de-senal" tabindex="-1">5. Considerar Ruido e Integridad de Señal <a class="header-anchor" href="#_5-considerar-ruido-e-integridad-de-senal" aria-label="Permalink to &quot;5. Considerar Ruido e Integridad de Señal&quot;">​</a></h3><p>Determinar si se requiere blindaje:</p><ul><li>Entornos con alto ruido (motores, VFD)</li><li>Señales sensibles (instrumentación, comunicación)</li></ul><p>Seleccionar el tipo de blindaje y método de puesta a tierra adecuados.</p><hr><h3 id="_6-verificar-normas-y-cumplimiento" tabindex="-1">6. Verificar Normas y Cumplimiento <a class="header-anchor" href="#_6-verificar-normas-y-cumplimiento" aria-label="Permalink to &quot;6. Verificar Normas y Cumplimiento&quot;">​</a></h3><p>Asegurar que la selección cumpla con:</p><ul><li>Normas aplicables (NEC, IEC o regulaciones locales)</li><li>Requisitos del equipo</li><li>Márgenes de seguridad</li></ul><hr><h2 id="ejemplo-motor-con-vfd" tabindex="-1">Ejemplo: Motor con VFD <a class="header-anchor" href="#ejemplo-motor-con-vfd" aria-label="Permalink to &quot;Ejemplo: Motor con VFD&quot;">​</a></h2><p><strong>Datos:</strong></p><ul><li>Potencia del motor: 30 HP</li><li>Voltaje: 460 V</li><li>Corriente a plena carga (FLC): 40 A</li></ul><p><strong>Paso 1: Aplicar factor de diseño</strong></p><ul><li>Ajuste por carga continua (ej. 125%):<br> 40 A × 1.25 = 50 A</li></ul><p><strong>Paso 2: Seleccionar tamaño de conductor</strong></p><ul><li>Elegir un cable con ampacidad ≥ 50 A</li></ul><p><strong>Paso 3: Verificar caída de voltaje</strong></p><ul><li>Evaluar según la longitud del cable</li><li>Aumentar tamaño si la caída es excesiva</li></ul><p><strong>Paso 4: Considerar efectos del VFD</strong></p><ul><li>Usar cable blindado para reducir ruido</li><li>Verificar aislamiento adecuado para operación con VFD</li></ul><p><strong>Resultado:</strong></p><ul><li>Un conductor equivalente a 6 AWG puede ser adecuado dependiendo de condiciones de instalación y normas aplicables</li></ul><hr><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>La selección de cables se utiliza en:</p><ul><li>Instalaciones de motores y variadores</li><li>Sistemas de distribución eléctrica</li><li>Sistemas de control y automatización</li><li>Instrumentación y medición</li><li>Redes de comunicación industrial</li></ul><hr><h2 id="consideraciones-clave" tabindex="-1">Consideraciones Clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones Clave&quot;">​</a></h2><p>Al seleccionar cables:</p><ul><li><strong>Desempeño eléctrico:</strong> ampacidad y caída de voltaje</li><li><strong>Tipo de aplicación:</strong> potencia vs señal</li><li><strong>Entorno:</strong> temperatura, humedad, químicos</li><li><strong>Condiciones mecánicas:</strong> flexibilidad, vibración, protección</li><li><strong>Entorno de ruido:</strong> necesidad de blindaje</li><li><strong>Cumplimiento normativo:</strong> seguridad y regulación</li></ul><hr><h2 id="notas-practicas" tabindex="-1">Notas Prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas Prácticas&quot;">​</a></h2><ul><li>La selección de cables es una decisión multidisciplinaria, no solo un cálculo eléctrico.</li><li>El cable más pequeño que cumple no siempre es la mejor opción; considerar confiabilidad y expansión futura.</li><li>Las aplicaciones con VFD requieren atención especial por ruido eléctrico y estrés en el aislamiento.</li><li>Las condiciones de instalación suelen tener mayor impacto que los cálculos teóricos.</li><li>La mayoría de los problemas relacionados con cables provienen de una mala selección o instalación, no del cable en sí.</li></ul>',69)])])}const h=a(n,[["render",c]]);export{m as __pageData,h as default};
